164		                   signal Clk : in std_logic) is
165		begin
166			wait until rising_edge(Clk);
167			Sig <= '1';
168			wait until rising_edge(Clk);
169			Sig <= '0';
170		end procedure;
171	
172		-- *** ClockedWaitFor ***
173		procedure ClockedWaitFor(Val        : in std_logic;
174		                         signal Sig : in std_logic;
175		                         signal Clk : in std_logic) is
176		begin
177			wait until rising_edge(Clk) and Sig = Val;
178		end procedure;
179		
180		-- *** ClockedWaitFor ***
181		procedure WaitClockCycles(	Cycles     : in integer;
182									signal Clk : in std_logic) is
183		begin
184			for i in 0 to Cycles-1 loop
185				wait until rising_edge(Clk);
186			end loop;
187		end procedure;
188		
189		-- *** ClockedWaitTime ***
190		procedure ClockedWaitTime(	Duration   	: in time;
191									signal Clk 	: in std_logic) is
192		begin
193			wait for Duration;
194			wait until rising_edge(Clk);
195		end procedure;
