199									freq_str   			: in real      := 1.0E6;
200									rst_pol_g  			: in std_logic := '1';
201									signal rst          : in std_logic;
202									signal clk        	: in std_logic;
203									signal str          : out std_logic) is
204	
205			variable count_v : integer range 0 to (integer(ceil(freq_clock/freq_str))) := 0;
206		begin
207			while true loop
208			wait until rising_edge(clk);
209			if rst = rst_pol_g then
210				count_v := 0;
211				str     <= '0';
212			else
213				if count_v /= integer(ceil(freq_clock/freq_str)) - 1 then
214					str     <= '0';
215					count_v := count_v + 1;
216				else
217					str     <= '1';
218					count_v := 0;
219				end if;
220			end if;
221			end loop;
222		end procedure;
223	
224		-- *** Wait for Standard logic vector to happen ***
225		procedure WaitForValueStdlv(signal Sig		: in std_logic_vector;
226									ExpVal			: in std_logic_vector;
227									Timeout	  		: in time;
228									Msg		  		: in string;
229									Prefix     		: in string := "###ERROR###: ") is
230		begin
231			wait until ExpVal = Sig for timeout;
232			if ExpVal /= Sig then
233				report 	Prefix & Msg & 
234					" Target state not reached" &
235					" [Expected " & str(ExpVal) & "(0x" & hstr(ExpVal) & ")" &
236					", Received " & str(Sig) & "(0x" & hstr(Sig) & ")" & "]"
237					severity error;
238			end if;
239		end procedure;
