248			wait until ExpVal = Sig for timeout;
249			if ExpVal /= Sig then
250				report Prefix & msg & 
251					" Target state not reached" &
252					" [Expected " & str(ExpVal) & 
253					", Received " & str(Sig) & "]" 
254					severity error;
255			end if;
256		end procedure;
257	
258	end psi_tb_activity_pkg;
