package body psi_tb_compare_pkg is

  -- *** IndexString ***
  function IndexString(Index : integer) return string is
  begin
    return "[" & to_string(Index) & "]";
  end function;

  -- *** StdlvCompareInt ***
  procedure StdlvCompareInt(Expected  : in integer;
