  end procedure;

  -- *** SignCompare2 ***
  procedure SignCompare2(Expected  : in signed;
                         Actual    : in signed;
                         Msg       : in string;
                         Tolerance : in integer := 0;
                         Prefix    : in string  := "###ERROR###: ") is
  begin
