            ", Received 0x" & hstr(std_logic_vector(Actual)) & 
            ", Tolerance " & to_string(Tolerance) & "]"
    severity error;
  end procedure;

  -- *** UsignCompare ***
  procedure UsignCompare(Expected  : in unsigned;
                         Actual    : in unsigned;
                         Msg       : in string;
