                         Prefix    : in string  := "###ERROR###: ") is
  begin
    assert (Actual >= Expected - Tolerance) and (Actual <= Expected + Tolerance)
    report Prefix & Msg & 
						" [Expected " & to_string(Expected) & 
						", Received " & to_string(Actual) & 
						", Tolerance " & to_string(Tolerance) & "]"
