  end procedure;

  -- *** SignCompareInt ***
  procedure SignCompareInt(Expected  : in integer;
                           Actual    : in signed;
                           Msg       : in string;
                           Tolerance : in integer := 0;
                           Prefix    : in string  := "###ERROR###: ") is
  begin
    StdlvCompareInt(Expected  => Expected,
                    Actual    => std_logic_vector(Actual),
                    Msg       => Msg,
                    IsSigned  => true,
                    Tolerance => Tolerance,
                    Prefix    => Prefix);
  end procedure;

  -- *** UsignCompareInt ***
  procedure UsignCompareInt(Expected  : in integer;
                            Actual    : in unsigned;
                            Msg       : in string;
                            Tolerance : in integer := 0;
                            Prefix    : in string  := "###ERROR###: ") is
  begin
    StdlvCompareInt(Expected  => Expected,
                    Actual    => std_logic_vector(Actual),
                    Msg       => Msg,
                    IsSigned  => false,
                    Tolerance => Tolerance,
                    Prefix    => Prefix);
